    if isinstance(node, ast.Import):
        for alias in node.names:
            modules.add(alias.name.split('.')[0])
    elif isinstance(node, ast.ImportFrom):
        if node.module:
            modules.add(node.module.split('.')[0])
sys.stdout.write('\n'.join(sorted(modules)) + '\n')

